export type BeadId = string;
export type BeadType = "wood" | "silicone" | "knit" | "plastic";

export interface BeadState {
  id: BeadId;
  type: BeadType;
  radius: number;
  color: string;
}

export interface ChainConfig {
  anchorPosition: [number, number, number];
  gravity: [number, number, number];
}

export interface ChainState {
  beads: BeadState[];
  config: ChainConfig;
}

"use client";

import { forwardRef, useRef } from "react";
import { RigidBody, BallCollider } from "@react-three/rapier";
import type { RapierRigidBody } from "@react-three/rapier";
import { useDrag } from "./DragControls";

export interface BeadRigidBodyProps {
  radius: number;
  color: string;
  /** Linear and angular damping (default: 2 — stabilizes chain swing). */
  damping?: number;
  position: [number, number, number];
}

/**
 * A single physics-driven bead: RigidBody + BallCollider + visual sphere.
 * Uses forwardRef so the parent can collect the RapierRigidBody ref for joints.
 * Supports pointer-drag via the useDrag hook (kinematic position pattern).
 */
export const BeadRigidBody = forwardRef<RapierRigidBody, BeadRigidBodyProps>(
  ({ radius, color, damping = 2, position }, ref) => {
    // useDrag needs its own ref to the same body; useForwardedRef pattern
    // won't work because useDrag reads from bodyRef.current in useFrame.
    // Instead, we pass the forwarded ref directly.
    const { onPointerDown, onPointerUp, onPointerOver, onPointerOut } =
      useDrag(ref);

    return (
      <RigidBody
        ref={ref}
        colliders={false}
        angularDamping={damping}
        linearDamping={damping}
        position={position}
        ccd={false}
      >
        <BallCollider args={[radius]} />
        <mesh
          castShadow
          onPointerDown={onPointerDown}
          onPointerUp={onPointerUp}
          onPointerOver={onPointerOver}
          onPointerOut={onPointerOut}
        >
          <sphereGeometry args={[radius, 32, 32]} />
          <meshStandardMaterial
            color={color}
            roughness={0.3}
            metalness={0.1}
          />
        </mesh>
      </RigidBody>
    );
  }
);

BeadRigidBody.displayName = "BeadRigidBody";

"use client";

import { useMemo } from "react";
import { RigidBody, BallCollider, useRopeJoint } from "@react-three/rapier";
import type { RapierRigidBody } from "@react-three/rapier";
import type { BeadState } from "@/types/bead";
import { BeadRigidBody } from "./BeadRigidBody";
import { ThreadLine } from "./ThreadLine";

// ── Constants ────────────────────────────────────────────────────────────────

/** Vertical distance between consecutive bead centres (world units). */
const BEAD_SPACING = 0.8;

/**
 * Rope max-length factor relative to BEAD_SPACING.
 * < 1.0 keeps the rope slightly taut (tension).
 */
const ROPE_TAUT_FACTOR = 0.92;

/** Radius of the fixed anchor ball. */
const ANCHOR_RADIUS = 0.12;

// ── JointLink ────────────────────────────────────────────────────────────────

/**
 * Thin wrapper that calls `useRopeJoint` for a single pair of bodies.
 * MUST be a separate component because React hooks cannot be called in loops.
 */
function JointLink({
  bodyA,
  bodyB,
  length,
}: {
  bodyA: React.RefObject<RapierRigidBody | null>;
  bodyB: React.RefObject<RapierRigidBody | null>;
  length: number;
}) {
  useRopeJoint(
    bodyA as React.RefObject<RapierRigidBody>,
    bodyB as React.RefObject<RapierRigidBody>,
    [[0, 0, 0], [0, 0, 0], length],
  );
  return null;
}

// ── BeadChain ────────────────────────────────────────────────────────────────

export interface BeadChainProps {
  /** Array of bead descriptors (position is computed from index). */
  beads: BeadState[];
  /** World-space position of the fixed anchor point. */
  anchorPosition: [number, number, number];
  /** Thread colour (default: "#8B4513" — saddle brown). */
  threadColor?: string;
}

/**
 * Full physics bead chain: fixed anchor → N dynamic beads connected by rope
 * joints → MeshLine thread that follows bead positions every frame.
 */
export function BeadChain({
  beads,
  anchorPosition,
  threadColor = "#8B4513",
}: BeadChainProps) {
  const [ax, ay, az] = anchorPosition;

  // ── Stable ref for the fixed anchor ───────────────────────────────────
  const anchorRef = useMemo(
    () => ({ current: null as RapierRigidBody | null }),
    [],
  );

  // ── Pre-create a stable ref object for every bead ─────────────────────
  // useMemo keyed on array length: new refs only when count changes.
  const beadRefs = useMemo(
    () =>
      beads.map(
        () => ({ current: null as RapierRigidBody | null }),
      ),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [beads.length],
  );

  // ── Compute initial bead positions (vertical column) ──────────────────
  const beadPositions = useMemo(
    () =>
      beads.map(
        (_, i) =>
          [ax, ay - (i + 1) * BEAD_SPACING, az] as [number, number, number],
      ),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [beads.length, ax, ay, az],
  );

  const ropeLength = BEAD_SPACING * ROPE_TAUT_FACTOR;

  return (
    <group>
      {/* ── Fixed anchor ─────────────────────────────────────────────── */}
      <RigidBody ref={anchorRef} type="fixed" position={anchorPosition}>
        <BallCollider args={[ANCHOR_RADIUS]} />
        <mesh>
          <sphereGeometry args={[ANCHOR_RADIUS, 24, 24]} />
          <meshStandardMaterial color="#444444" roughness={0.5} metalness={0.4} />
        </mesh>
      </RigidBody>

      {/* ── Dynamic beads ───────────────────────────────────────────── */}
      {beads.map((bead, i) => (
        <BeadRigidBody
          key={bead.id}
          ref={beadRefs[i]}
          radius={bead.radius}
          color={bead.color}
          damping={2}
          position={beadPositions[i]}
        />
      ))}

      {/* ── Rope joints ─────────────────────────────────────────────── */}
      {/* anchor → bead[0] */}
      {beads.length > 0 && (
        <JointLink
          bodyA={anchorRef}
          bodyB={beadRefs[0]}
          length={ropeLength}
        />
      )}
      {/* bead[i] → bead[i+1] */}
      {beads.slice(1).map((bead, i) => (
        <JointLink
          key={`joint-${bead.id}`}
          bodyA={beadRefs[i]}
          bodyB={beadRefs[i + 1]}
          length={ropeLength}
        />
      ))}

      {/* ── Thread line visualisation ───────────────────────────────── */}
      <ThreadLine
        anchorPosition={anchorPosition}
        anchorRef={anchorRef}
        beadRefs={beadRefs}
        beadCount={beads.length}
        color={threadColor}
      />
    </group>
  );
}

"use client";

import { useRef, useMemo } from "react";
import { useFrame, useThree, extend } from "@react-three/fiber";
import { MeshLineGeometry, MeshLineMaterial } from "meshline";
import * as THREE from "three";
import type { RapierRigidBody } from "@react-three/rapier";

// Register meshline classes with R3F's renderer
extend({ MeshLineGeometry, MeshLineMaterial });

// Augment R3F JSX types so TypeScript recognises <meshLineGeometry> / <meshLineMaterial>
declare module "@react-three/fiber" {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  interface ThreeElements {
    meshLineGeometry: ThreeElements["bufferGeometry"] & {
      ref?: React.Ref<MeshLineGeometry>;
      args?: ConstructorParameters<typeof MeshLineGeometry>;
    };
    // MeshLineMaterial extends ShaderMaterial with custom props (color, lineWidth, resolution, etc.)
    meshLineMaterial: {
      ref?: React.Ref<MeshLineMaterial>;
      color?: string | number | THREE.Color;
      lineWidth?: number;
      resolution?: THREE.Vector2;
      sizeAttenuation?: boolean;
      opacity?: number;
      dashArray?: number;
      dashOffset?: number;
      dashRatio?: number;
      useDash?: number;
      useGradient?: number;
      visibility?: number;
      map?: THREE.Texture;
      alphaMap?: THREE.Texture;
      transparent?: boolean;
      attach?: string;
      args?: ConstructorParameters<typeof MeshLineMaterial>;
    };
  }
}

export interface ThreadLineProps {
  /** World-space position of the fixed anchor (first point on the curve). */
  anchorPosition: [number, number, number];
  /** Ref to the anchor's RapierRigidBody (for reading live position). */
  anchorRef: React.RefObject<RapierRigidBody | null>;
  /** Stable ref objects for each bead, indexed by position. */
  beadRefs: React.RefObject<RapierRigidBody | null>[];
  /** Number of beads — geometry update is skipped until all refs are populated. */
  beadCount: number;
  /** Thread colour. */
  color: string;
  /** MeshLine width in world units (default 0.015). */
  lineWidth?: number;
}

// Reusable vectors to avoid GC pressure in useFrame
const _v = new THREE.Vector3();

/**
 * Renders a smooth MeshLine curve that passes through the anchor and every bead.
 * Updated every frame from Rapier body translation positions.
 */
export function ThreadLine({
  anchorPosition,
  anchorRef,
  beadRefs,
  beadCount,
  color,
  lineWidth = 0.015,
}: ThreadLineProps) {
  const geoRef = useRef<MeshLineGeometry>(null);
  const matRef = useRef<MeshLineMaterial>(null);
  const { size } = useThree();

  // Keep resolution in sync with the canvas (needed by MeshLineMaterial shader)
  const resolution = useMemo(
    () => new THREE.Vector2(size.width, size.height),
    [size.width, size.height],
  );

  // Reusable points array to avoid allocation every frame
  const points = useMemo(() => [] as THREE.Vector3[], []);

  useFrame(() => {
    if (!geoRef.current) return;

    // Wait until every bead ref is populated
    if (beadRefs.length < beadCount) return;
    for (let i = 0; i < beadCount; i++) {
      if (!beadRefs[i].current) return;
    }

    // Build point list: anchor position → bead0 → bead1 → …
    points.length = 0;

    // Prefer live anchor position from physics (falls back to static prop)
    const anchorBody = anchorRef.current;
    if (anchorBody) {
      const p = anchorBody.translation();
      _v.set(p.x, p.y, p.z);
    } else {
      _v.set(anchorPosition[0], anchorPosition[1], anchorPosition[2]);
    }
    points.push(_v.clone());

    for (let i = 0; i < beadCount; i++) {
      const body = beadRefs[i].current!;
      const p = body.translation();
      points.push(new THREE.Vector3(p.x, p.y, p.z));
    }

    // CatmullRom spline through all points → smooth thread
    const curve = new THREE.CatmullRomCurve3(points, false, "catmullrom", 0.5);
    geoRef.current.setPoints(curve.getPoints(32));
  });

  return (
    <mesh>
      <meshLineGeometry ref={geoRef} />
      <meshLineMaterial
        ref={matRef}
        color={color}
        lineWidth={lineWidth}
        resolution={resolution}
        sizeAttenuation
      />
    </mesh>
  );
}

"use client";

import { Suspense } from "react";
import { Canvas } from "@react-three/fiber";
import { Physics } from "@react-three/rapier";
import { OrbitControls, Environment, ContactShadows, Stats } from "@react-three/drei";
import { BeadChain } from "./BeadChain";
import type { BeadState } from "@/types/bead";

export interface SceneProps {
  /** Array of bead descriptors — drives chain composition. */
  beads: BeadState[];
}

/**
 * Root 3D scene: Canvas → Physics → BeadChain → ThreadLine.
 * SSR-safe (loaded via SceneLoader with dynamic ssr:false).
 */
export default function Scene({ beads }: SceneProps) {
  return (
    <Canvas
      camera={{ position: [0, 1, 7], fov: 50 }}
      shadows
      style={{ background: "linear-gradient(180deg, #f0f4f8 0%, #d9e2ec 100%)" }}
    >
      {/* Soft gradient background */}
      <color attach="background" args={["#eef2f6"]} />
      <fog attach="fog" args={["#eef2f6", 12, 22]} />

      {/* Lighting: soft studio feel */}
      <ambientLight intensity={0.3} />
      <directionalLight
        position={[5, 8, 5]}
        intensity={1}
        castShadow
        shadow-mapSize-width={1024}
        shadow-mapSize-height={1024}
      />
      {/* Fill light from opposite side for softer shadows */}
      <directionalLight position={[-3, 5, -3]} intensity={0.3} />

      <Suspense fallback={null}>
        <Environment preset="studio" />

        {/* Physics world: gravity tuned for snappy feel (Vercel pattern) */}
        <Physics gravity={[0, -40, 0]}>
          <BeadChain beads={beads} anchorPosition={[0, 3, 0]} />
        </Physics>

        {/* Soft ground shadow */}
        <ContactShadows
          position={[0, -3, 0]}
          opacity={0.4}
          scale={10}
          blur={2}
          far={4}
        />
      </Suspense>

      <OrbitControls
        makeDefault
        minPolarAngle={0}
        maxPolarAngle={Math.PI}
        minDistance={2}
        maxDistance={20}
      />

      {/* FPS overlay — visible in dev only */}
      <Stats />
    </Canvas>
  );
}

import SceneLoader from "@/components/SceneLoader";

export default function Home() {
  return <SceneLoader />;
}

/// <reference types="vitest/config" />
import { defineConfig } from "vitest/config";
import react from "@vitejs/plugin-react";

export default defineConfig({
  plugins: [react()],
  test: {
    environment: "jsdom",
    setupFiles: ["./src/test-setup.ts"],
    passWithNoTests: true,
  },
});

"use client";

import dynamic from "next/dynamic";
import { useBeadChain } from "@/hooks/useBeadChain";

// Dynamically import the Scene to avoid SSR issues with Three.js / WebGL
const Scene = dynamic(() => import("@/components/scene/Scene"), {
  ssr: false,
});

/**
 * Client-side wrapper that owns bead chain state and passes it to the Scene.
 * Also renders minimal overlay UI for demo purposes.
 */
export default function SceneLoader() {
  const { beads, addBead, removeLast, reset } = useBeadChain();

  return (
    <div className="relative w-screen h-screen">
      {/* 3D Canvas fills the viewport */}
      <Scene beads={beads} />

      {/* ── Overlay UI ──────────────────────────────────────────────── */}

      {/* Title */}
      <div className="absolute top-4 left-4 select-none pointer-events-none">
        <h1 className="text-lg font-semibold text-gray-700 tracking-tight">
          Bead Chain
        </h1>
        <p className="text-xs text-gray-400 mt-0.5">
          Drag beads to interact
        </p>
      </div>

      {/* Controls panel */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-2 rounded-full bg-white/70 backdrop-blur-md shadow-lg px-4 py-2 border border-gray-200/50">
        <span className="text-sm text-gray-500 mr-2">{beads.length} beads</span>

        <button
          onClick={() => addBead()}
          className="px-3 py-1.5 text-sm font-medium rounded-full bg-emerald-50 text-emerald-700 hover:bg-emerald-100 transition-colors cursor-pointer"
        >
          + Add
        </button>

        <button
          onClick={removeLast}
          disabled={beads.length === 0}
          className="px-3 py-1.5 text-sm font-medium rounded-full bg-rose-50 text-rose-700 hover:bg-rose-100 transition-colors disabled:opacity-40 disabled:cursor-not-allowed cursor-pointer"
        >
          − Remove
        </button>

        <button
          onClick={reset}
          className="px-3 py-1.5 text-sm font-medium rounded-full bg-gray-50 text-gray-700 hover:bg-gray-100 transition-colors cursor-pointer"
        >
          ↺ Reset
        </button>
      </div>
    </div>
  );
}

